import * as t from "io-ts";
import { StakeIntent } from "./stakeIntent";
import { Optional, optionalString } from "../../../utils";
import { Amount } from "./amount";
import { RecipientEntry } from "./recipientEntry";

/**
 * @title SUI Stake Intent
 */
export const SuiStakingIntent = t.intersection([
  StakeIntent,
  t.partial({
    validatorAddress: optionalString,
    amount: Optional(Amount),
    recipients: Optional(t.array(RecipientEntry)),
  }),
]);

export type SuiStakingIntent = t.TypeOf<typeof SuiStakingIntent>;
